  1→/**
  2→ * CategoryRepository — CRUD with hierarchy support
  3→ *
  4→ * Provides typed methods for Category queries with parentId cycle detection,
  5→ * type filtering (income/expense), and soft-delete via isActive flag.
  6→ * All errors propagate to caller for handling at API layer.
  7→ */
  8→
  9→import { prisma } from './prisma';
 10→import type {
 11→  Category,
 12→  Prisma,
 13→} from '@prisma/client';
 14→import { randomUUID } from 'node:crypto';
 15→
 16→export type CategoryCreateInput = Omit<
 17→  Prisma.CategoryUncheckedCreateInput,
 18→  'id' | 'updatedAt'
 19→> &
 20→  Partial<Pick<Prisma.CategoryUncheckedCreateInput, 'id' | 'updatedAt'>>;
 21→
 22→export type CategoryUpdateInput = Prisma.CategoryUncheckedUpdateInput;
 23→
 24→export class CategoryRepository {
 25→  /**
 26→   * Flat list of active categories, sorted by parentId (nulls first), then order.
 27→   * Suitable for building a tree in the UI.
 28→   */
 29→  async findTree(): Promise<Category[]> {
 30→    return prisma.category.findMany({
 31→      where: { isActive: true },
 32→      orderBy: [{ parentId: { sort: 'asc', nulls: 'first' } }, { order: 'asc' }],
 33→    });
 34→  }
 35→
 36→  /**
 37→   * Find categories by type (income / expense).
 38→   * Only returns active categories.
 39→   */
 40→  async findByType(type: string): Promise<Category[]> {
 41→    return prisma.category.findMany({
 42→      where: { type, isActive: true },
 43→      orderBy: { order: 'asc' },
 44→    });
 45→  }
 46→
 47→  /**
 48→   * Find a single active category by ID.
 49→   */
 50→  async findUnique(id: string): Promise<Category | null> {
 51→    return prisma.category.findFirst({
 52→      where: { id, isActive: true },
 53→    });
 54→  }
 55→
 56→  /**
 57→   * Create a new category.
 58→   * Validates parentId existence and cycle prevention.
 59→   */
 60→  async create(data: CategoryCreateInput): Promise<Category> {
 61→    if (data.parentId) {
 62→      await this._validateParent(data.parentId);
 63→    }
 64→
 65→    return prisma.category.create({
 66→      data: {
 67→        ...data,
 68→        id: data.id ?? randomUUID(),
 69→        updatedAt: data.updatedAt ?? new Date(),
 70→      },
 71→    });
 72→  }
 73→
 74→  /**
 75→   * Update an existing category.
 76→   * Validates parentId existence, cycle prevention, and target existence.
 77→   */
 78→  async update(id: string, data: CategoryUpdateInput): Promise<Category> {
 79→    const existing = await this.findUnique(id);
 80→    if (!existing) {
 81→      throw new Error(`Category with id ${id} not found`);
 82→    }
 83→
 84→    if (data.parentId !== undefined) {
 85→      if (data.parentId === id) {
 86→        throw new Error('Category cannot be its own parent');
 87→      }
 88→      if (data.parentId !== null) {
 89→        await this._validateParent(String(data.parentId), id);
 90→      }
 91→    }
 92→
 93→    return prisma.category.update({
 94→      where: { id },
 95→      data,
 96→    });
 97→  }
 98→
 99→  /**
100→   * Soft-delete: sets isActive = false.
101→   * Refuses if category is referenced by active Budget or Transaction records.
102→   */
103→  async delete(id: string): Promise<Category> {
104→    const existing = await this.findUnique(id);
105→    if (!existing) {
106→      throw new Error(`Category with id ${id} not found`);
107→    }
108→
109→    // Check Budget references
110→    const budgetCount = await prisma.budget.count({
111→      where: { categoryId: id },
112→    });
113→    if (budgetCount > 0) {
114→      throw new Error(
115→        `Cannot delete category ${id}: referenced by ${budgetCount} budget(s)`
116→      );
117→    }
118→
119→    // Check Transaction references (non-deleted)
120→    const txCount = await prisma.transaction.count({
121→      where: { categoryId: id, deletedAt: null },
122→    });
123→    if (txCount > 0) {
124→      throw new Error(
125→        `Cannot delete category ${id}: referenced by ${txCount} transaction(s)`
126→      );
127→    }
128→
129→    return prisma.category.update({
130→      where: { id },
131→      data: { isActive: false, updatedAt: new Date() },
132→    });
133→  }
134→
135→  /**
136→   * Count active categories matching optional criteria.
137→   */
138→  async count(where?: Prisma.CategoryWhereInput): Promise<number> {
139→    return prisma.category.count({
140→      where: { ...where, isActive: true },
141→    });
142→  }
143→
144→  // ── private helpers ──────────────────────────────────────────────
145→
146→  /**
147→   * Validate parentId: must reference an active category.
148→   * If excludeId is provided, also checks for cycles.
149→   */
150→  private async _validateParent(
151→    parentId: string,
152→    excludeId?: string
153→  ): Promise<void> {
154→    const parent = await prisma.category.findFirst({
155→      where: { id: parentId, isActive: true },
156→    });
157→    if (!parent) {
158→      throw new Error(
159→        `Parent category ${parentId} not found or is inactive`
160→      );
161→    }
162→
163→    if (excludeId) {
164→      const wouldCycle = await this._wouldCreateCycle(parentId, excludeId);
165→      if (wouldCycle) {
166→        throw new Error(
167→          `Setting parentId=${parentId} would create a cycle for category ${excludeId}`
168→        );
169→      }
170→    }
171→  }
172→
173→  /**
174→   * Walk the parent chain upward from startId.
175→   * Returns true if we encounter targetId, indicating a cycle.
176→   */
177→  private async _wouldCreateCycle(
178→    startId: string,
179→    targetId: string
180→  ): Promise<boolean> {
181→    const visited = new Set<string>();
182→    let currentId: string | null = startId;
183→
184→    while (currentId !== null) {
185→      if (currentId === targetId) return true;
186→      if (visited.has(currentId)) return true; // already a cycle in DB
187→      visited.add(currentId);
188→
189→      const cat = await prisma.category.findUnique({
190→        where: { id: currentId },
191→        select: { parentId: true },
192→      });
193→      currentId = cat?.parentId ?? null;
194→    }
195→
196→    return false;
197→  }
198→}
199→
200→/** Singleton instance */
201→export const categories = new CategoryRepository();
202→export default categories;
203→

